E = int(input())
D = int(input())
if E > D:
    print(E + D)
else:
    print(2 * (D - E))

n, q = map(int, input().split())
grid = [list(map(int, list(input().strip()))) for _ in range(n)]

for _ in range(q):
    new_grid = []
    for i in range(n):
        new_row = []
        for j in range(n):
            count = 0
            for dx in (-1, 0, 1):
                for dy in (-1, 0, 1):
                    if dx == 0 and dy == 0:
                        continue
                    ni, nj = i + dx, j + dy
                    if 0 <= ni < n and 0 <= nj < n:
                        count += grid[ni][nj]
            if grid[i][j] == 1:
                new_row.append(1 if count in (2, 3) else 0)
            else:
                new_row.append(1 if count == 3 else 0)
        new_grid.append(new_row)
    grid = new_grid

for row in grid:
    print(''.join(map(str, row)))
